'use strict'

/* / const API_ADDR = 'http://91.218.229.81:8000/'  // разработческий
/*/ const API_ADDR = 'http://116.203.39.144:8000/'
/* */

onmessage = ev => {
	function checkParam(...params) {
		params.forEach(param => {
			if (ev.data[param] == undefined)
				throw `Вызов метода ${ev.data.type} требует передачи параметра ${param}.\nПередано: ${JSON.stringify(ev.data)}`
		})
	}

	if (!('type' in ev.data)) {
		console.error('Плохой вызов воркера, нужно передать параметр type: %o', ev.data)
		return
	}

	let params = {}
	switch (ev.data.type) {

		// Попытка логина
		case 'login':
			checkParam('login', 'password')

			API({
				name: 'jwt/login/',
				method: 'post',
				postData: JSON.stringify({
					username: ev.data.login,
					password: ev.data.password
				})
			}, login => {
				if (login.token) {
					const token = login.token
					const uID = JSON.parse(atob(token.split('.')[1].replace('-', '+').replace('_', '/'))).user_id

					// Сразу запрашиваем информацию о пользвоателе
					API({
						name: 'user/current_user/',
						token: token
					}, uinfo => {
						if (!uinfo.groups || !uinfo.groups.length)
							throw 'Пользователь не состоит ни в одной группе'

						postMessage({
							type: 'login',
							result: 'ok',
							token: token,
							user: uinfo
						})
					})
				}
			})
			break

		// Подробная информация о пользователе
		case 'userInfo':
			checkParam('token')

			API({
				name: `user/current_user/`,
				token: ev.data.token
			}, answer => {
				if (!answer.groups || !answer.groups.length)
					throw 'Пользователь не состоит ни в одной группе'

				postMessage({
					type: ev.data.type,
					user: answer
				})
			})
			break

		// Список записей
		case 'records':
			checkParam('token', 'page', 'pageSize', 'filters')

			params = {
				page: ev.data.page,
				page_size: ev.data.pageSize,
				status: 'system_verified'
			}

			if (ev.data.filters.wave != '-1') params.monitoring_wave = ev.data.filters.wave
			if (ev.data.filters.net != '-1') params.retail_network = ev.data.filters.net
			if (ev.data.filters.tradePoint && ev.data.filters.tradePoint != '-1') params.shops = ev.data.filters.tradePoint
			if (ev.data.filters.dateFrom) params.begin = ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.dateTo) params.end = ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.auditor && ['sent', 'priceless', 'moderation'].indexOf(ev.data.filters.tab) != -1) params.auditor_fio = ev.data.filters.auditor
			if (ev.data.filters.priceNotChanged && ev.data.filters.priceNotChanged == 1 && ev.data.filters.tab == 'sent') params.price_not_changed = true
			if (ev.data.filters.segment && ev.data.filters.segment != '-1') params.segment = ev.data.filters.segment
			if (ev.data.filters.tab == 'priceless') params.status = 'without_price'
			if (ev.data.filters.tab == 'moderation') params.status = 'on_moderation'
			if (ev.data.filters.tab == 'deleted') params.status = 'deleted'

			/* Фильтры по процентам */
			if (['moderation', 'sent'].indexOf(ev.data.filters.tab) != -1) {
				if (ev.data.filters.perc_card_current && ev.data.filters.perc_card_current.length) params.card_current_diff_percent = ev.data.filters.perc_card_current
				if (ev.data.filters.perc_sale_current && ev.data.filters.perc_sale_current.length) params.sale_current_diff_percent = ev.data.filters.perc_sale_current
				if (ev.data.filters.perc_average && ev.data.filters.perc_average.length) params.average_diff_percent = ev.data.filters.perc_average
				if (ev.data.filters.perc_general_previous && ev.data.filters.perc_general_previous.length) params.general_previous_diff_percent = ev.data.filters.perc_general_previous
				if (ev.data.filters.perc_card_previous && ev.data.filters.perc_card_previous.length) params.card_previous_diff_percent = ev.data.filters.perc_card_previous
				if (ev.data.filters.perc_sale_previous && ev.data.filters.perc_sale_previous.length) params.sale_previous_diff_percent = ev.data.filters.perc_sale_previous
			}

			if (ev.data.sorting) params.order = ev.data.sorting

			API({
				name: 'sku_monitoring_data/',
				token: ev.data.token,
				getParams: params
			}, answer => {
				if (!('count' in answer))
					throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

				if (answer.count)
					answer.results.forEach((res, idx) => {
						res.checked = false
						addSkuToRecord(res)
					})

				postMessage({
					type: ev.data.type,
					records: (answer.count ? answer.results : []),
					count: answer.count
				})
			})
			break

		// Получение соседних записей для открытой
		case 'getRecordNeighbours':
			checkParam('token', 'id', 'filters')

			params = { page_size: 1 }

			if (ev.data.filters.wave !== undefined && ev.data.filters.wave != '-1') params.monitoring_wave = ev.data.filters.wave
			if (ev.data.filters.net !== undefined && ev.data.filters.net != '-1') params.retail_network = ev.data.filters.net
			if (ev.data.filters.tradePoint && ev.data.filters.tradePoint !== undefined && ev.data.filters.tradePoint != '-1') params.shops = ev.data.filters.tradePoint
			if (ev.data.filters.dateFrom) params.begin = ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.dateTo) params.end = ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.auditor && ['sent', 'priceless', 'moderation'].indexOf(ev.data.filters.tab) != -1) params.auditor_fio = ev.data.filters.auditor
			if (ev.data.filters.priceNotChanged && ev.data.filters.tab == 'sent') params.price_not_changed = (ev.data.filters.priceNotChanged == 1)
			if (ev.data.filters.segment && ev.data.filters.segment != '-1') params.segment = ev.data.filters.segment
			if (ev.data.filters.tab == 'sent') params.status = 'system_verified'
			if (ev.data.filters.tab == 'priceless') params.status = 'without_price'
			if (ev.data.filters.tab == 'moderation') params.status = 'on_moderation'
			if (ev.data.filters.tab == 'noitem') params.status = 'wrong_sku_name'
			if (ev.data.filters.tab == 'nobarcode') params.status = 'new_barcode'

			/* Фильтры по процентам */
			if (ev.data.filters.perc_card_current && ev.data.filters.perc_card_current.length) params.card_current_diff_percent = ev.data.filters.perc_card_current
			if (ev.data.filters.perc_sale_current && ev.data.filters.perc_sale_current.length) params.sale_current_diff_percent = ev.data.filters.perc_sale_current
			if (ev.data.filters.perc_average && ev.data.filters.perc_average.length) params.average_diff_percent = ev.data.filters.perc_average
			if (ev.data.filters.perc_general_previous && ev.data.filters.perc_general_previous.length) params.general_previous_diff_percent = ev.data.filters.perc_general_previous
			if (ev.data.filters.perc_card_previous && ev.data.filters.perc_card_previous.length) params.card_previous_diff_percent = ev.data.filters.perc_card_previous
			if (ev.data.filters.perc_sale_previous && ev.data.filters.perc_sale_previous.length) params.sale_previous_diff_percent = ev.data.filters.perc_sale_previous

			if (ev.data.sorting) params.order = ev.data.sorting

			API({
				name: `sku_monitoring_data/`,
				token: ev.data.token,
				getParams: Object.assign({next: ev.data.id},  params)
			}, answer => {
				postMessage({
					type: 'nextRecord',
					record: answer.count ? addSkuToRecord(answer.results[0]) : null
				})
			})

			API({
				name: `sku_monitoring_data/`,
				token: ev.data.token,
				getParams: Object.assign({previous: ev.data.id},  params)
			}, answer => {
				postMessage({
					type: 'prevRecord',
					record: answer.count ? addSkuToRecord(answer.results[0]) : null
				})
			})
			break

		// Сохранение изменений в записи
		case 'saveRecords':
			checkParam('token', 'records')

			// Выбираем только те записи, у которых установлена хотя бы одна цена
			const toSave = ev.data.records.filter(R => {
				return ((R.general_price !== '' && R.general_price !== null)
				|| (R.card_price !== '' && R.card_price !== null)
				|| (R.sale_price !== '' && R.sale_price !== null))
			})

			if (!toSave.length) break

			toSave.forEach(R => {
				if (R.general_price === '') R.general_price = null
				if (R.card_price === '') R.card_price = null
				if (R.sale_price === '') R.sale_price = null
				R.sku = R.sku.barcode
			})

			API({
				name: 'sku_monitoring_data/batch/',
				method: 'post',
				token: ev.data.token,
				postData: JSON.stringify(toSave),
			}, answer => {
				postMessage({
					type: 'recordsSaved',
					keepDetails: !!ev.data.keepDetails
				})
			})
			break

		case 'deleteRecord':
			checkParam('token', 'id')

			// Ответ на этот запрос перехватывается костылём, потому что он без тела
			API({
				name: `sku_monitoring_data/${ev.data.id}/`,
				method: 'delete',
				token: ev.data.token
			})
			break

		case 'sku':
			checkParam('token', 'page', 'pageSize', 'filters')

			params = {
				page: ev.data.page,
				page_size: ev.data.pageSize
			}

			if (ev.data.filters.tab == 'fullbase') {
				if (ev.data.filters.segment  != '-1') params.segment = ev.data.filters.segment
				if (ev.data.filters.brand    != '') params.brand = ev.data.filters.brand
				if (ev.data.filters.barcode  != '') params.barcode = ev.data.filters.barcode
				if (ev.data.filters.producer != '') params.producer = ev.data.filters.producer

				API({
					name: 'sku/',
					token: ev.data.token,
					getParams: params
				}, answer => {
					if (!('count' in answer))
						throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

					if (answer.count)
						answer.results.forEach((res, idx) => {
							res.checked = false
						})

					postMessage({
						type: ev.data.type,
						sku: (answer.count ? answer.results : []),
						count: answer.count
					})
				})
			}
			else {
				// Запросы на API для записей, потому что тут на самом деле записи
				if (ev.data.filters.segment  != '-1') params.segment = ev.data.filters.segment
				if (ev.data.filters.barcode) params.sku = ev.data.filters.barcode
				if (ev.data.filters.dateFrom) params.begin = ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
				if (ev.data.filters.dateTo) params.end = ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
				if (ev.data.filters.tab == 'nobarcode') {
					if (ev.data.filters.auditor) params.auditor_fio = ev.data.filters.auditor 
					if (ev.data.filters.town) params.address = ev.data.filters.town 
					if (ev.data.filters.net !== undefined && ev.data.filters.net != -1) params.retail_network = ev.data.filters.net 
				}
				if (ev.data.filters.tab == 'noitem') params.status = 'wrong_sku_name'
				if (ev.data.filters.tab == 'nobarcode') params.status = 'new_barcode'

				API({
					name: 'sku_monitoring_data/',
					token: ev.data.token,
					getParams: params
				}, answer => {
					if (!('count' in answer))
						throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

					if (answer.count)
						answer.results.forEach(res => {
							res.checked = false
							addSkuToRecord(res)
						})

					postMessage({
						type: ev.data.type,
						sku: (answer.count ? answer.results : []),
						count: answer.count
					})
				})
			}
			break

		// Получение деталей конкретного sku
		case 'getSku':
			checkParam('token', 'barcode', 'idx')

			API({
				name: `sku/${ev.data.barcode}/`,
				token: ev.data.token
			}, answer => {
				postMessage({
					type: ev.data.idx >= 0 ? 'skuInfo': 'skuDetailInfo',
					sku: answer,
					idx: ev.data.idx
				})
			})
			break

		// Добавление нового sku
		case 'addSku':
			checkParam('token', 'formData')

			if (!ev.data.formData.barcode.length) {
				postMessage({ type: 'addSkuError', errorField: 'barcode' })
				break
			}
			if (!ev.data.formData.itemName.length) {
				postMessage({ type: 'addSkuError', errorField: 'itemName' })
				break
			}
			if (!ev.data.formData.brand.length) {
				postMessage({ type: 'addSkuError', errorField: 'brand' })
				break
			}
			if (!ev.data.formData.producer.length) {
				postMessage({ type: 'addSkuError', errorField: 'producer' })
				break
			}
			if (!ev.data.formData.segment) {
				postMessage({ type: 'addSkuError', errorField: 'segment' })
				break
			}

			params = {
				barcode:  ev.data.formData.barcode,
				name:     ev.data.formData.itemName,
				brand:    ev.data.formData.brand,
				producer: ev.data.formData.producer,
				segment:  ev.data.formData.segment
			}

			API({
				name: 'sku/',
				method: 'post',
				token: ev.data.token,
				postData: JSON.stringify(params)
			}, answer => {
				postMessage({
					type: 'skuAdded',
					sku: answer
				})
			})
			break

		// Сохранение изменённых данных на вкладках "Товар не верен" и "Штрихкода нет в базе"
		case 'saveSku':
			// filter содержит noitem или nobarcode — вкладку из sku
			checkParam('token', 'list', 'filter')

			const isNoItem = ev.data.filter == 'noitem'
			var changedSku
			//if (isNoItem)
				changedSku = ev.data.list.filter(rec => rec.checked && rec.sku.brand.length)
			/*else
				changedSku = ev.data.list.filter(rec => rec.checked && rec.sku.brand.length && rec.sku.producer.length && rec.sku.name.length)*/

			var sentCount = changedSku.length

			for (let chCount = sentCount, z = 0; z < chCount; ++z) {
				const sku = changedSku[z].sku
				sku.segment = sku.segment.code

				// Если штрихкод не меняли, редактируем его, а если меняли, привязываем к записи другой
				if (sku.barcode == sku.srcBarcode) {
					API({
						name: isNoItem ? `sku/${sku.barcode}/` : 'sku/',
						method: isNoItem ? 'put' : 'post',
						token: ev.data.token,
						postData: JSON.stringify(sku)
					}, answer => {
						if (--sentCount == 0)
							postMessage({
								type: 'skuChanged',
								keepDetails: !!ev.data.keepDetails
							})
					})
				}
				else {
					API({
						name: `sku_monitoring_data/batch/`,
						method: 'post',
						token: ev.data.token,
						postData: JSON.stringify([{id: changedSku[z].id, sku: Number(sku.barcode)}])
					}, answer => {
						if (--sentCount == 0)
							postMessage({
								type: 'skuChanged',
								keepDetails: !!ev.data.keepDetails
							})
					})
				}
			}
			break

		// Редактирование sku
		case 'editSku':
			checkParam('token', 'sku')

			const sku = ev.data.sku
			sku.segment = sku.segment.code			
			API({
				name: `sku/${sku.barcode}/`,
				method: 'patch',
				token: ev.data.token,
				postData: JSON.stringify(sku)
			})
			break

		// Список пользователей
		case 'users':
			checkParam('token', 'page', 'pageSize', 'filters')

			params = {
				page: ev.data.page,
				page_size: ev.data.pageSize
			}

			if (ev.data.filters.lastName) params[('isMentor' in ev.data && ev.data.isMentor) ? 'auditor_fio' : 'fio'] = ev.data.filters.lastName
			if (ev.data.filters.login) params.username = ev.data.filters.login

			const mentorUsers = 'isMentor' in ev.data && ev.data.isMentor ? 'auditors_for_mentor/' : ''

			API({
				name: 'user/' + mentorUsers,
				token: ev.data.token,
				getParams: params
			}, answer => {
				postMessage({
					type: ev.data.type,
					users: answer
				})
			})
			break

		case 'mentors':
			checkParam('token')

			API({
				name: 'user/',
				token: ev.data.token,
				getParams: {
					group: 'Наставник',
					page: 1,
					page_size: 1e5
				}
			}, answer => {
				postMessage({
					type: ev.data.type,
					mentors: answer.count ? answer.results.sort((A, B) => `${A.first_name} ${A.last_name}` > `${B.first_name} ${B.last_name}`) : []
				})
			})
			break

		// Список клиентов
		case 'clients':
			checkParam('token')

			API({
				name: 'customer/',
				token: ev.data.token,
				getParams: {
					page: 1,
					page_size: 1e5
				}
			}, answer => {
				if ('count' in answer && 'results' in answer)
					postMessage({
						type: ev.data.type,
						clients: (answer.count ? answer.results : [])
					})
				else
					throw `на запрос ${ev.data.type} сервер прислал плохой ответ`
			})
			break

		// Список волн для фильтра
		case 'wavesFilter':
			checkParam('token', 'client')

			if ('client' in ev.data && ev.data.client !== -1)
				params = { customer: ev.data.client } 

			API({
				name: 'monitoring_wave/filter/',
				token: ev.data.token,
				getParams: params
			}, answer => {
				postMessage({
					type: ev.data.type,
					waves: answer
				})
			})
			break

		// Список сетей волны
		case 'networks':
			checkParam('token', 'wave')

			API({
				name: 'retail_network/monitoring_wave/filter/',
				token: ev.data.token,
				getParams: {
					monitoring_wave: ev.data.wave
				}
			}, answer => {
				postMessage({
					type: ev.data.type,
					networks: answer
				})
			})
			break

		// Список всех сетей
		case 'all_networks':
			checkParam('token')

			API({
				name: 'retail_network/',
				token: ev.data.token,
				getParams: {
					page: 1,
					page_size: 1e5
				}
			}, answer => {
				postMessage({
					type: ev.data.type,
					nets: answer.count ? answer.results : []
				})
			})
			break

		// Список торговых точек
		case 'tradePoints':
			checkParam('token', 'wave')

			API({
				name: 'shop/monitoring_wave/filter/',
				token: ev.data.token,
				getParams: {
					monitoring_wave: ev.data.wave
				}
			}, answer => {
				postMessage({
					type: ev.data.type,
					tradePoints: answer
				})
			})
			break

		// Список сегментов
		case 'segments':
			checkParam('token')

			API({
				name: 'segment/',
				token: ev.data.token,
				getParams: {
					page: 1,
					page_size: 1e5
				}
			}, answer => {
				if (!('count' in answer))
					throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

				if (answer.count)
					answer.results.forEach(res => {
						res.id = res.code
					})

				postMessage({
					type: ev.data.type,
					segments: answer.results
				})
			})
			break

		// Список аудиторов для выпадашек
		case 'auditorsFilter':
			checkParam('token')

			API({
				name: 'user/auditors_for_mentor',
				token: ev.data.token,
				getParams: {
					page: 1,
					page_size: 150
				}
			}, answer => {
				const result = answer.map(R => {
					return {
						id: R.id,
						name: `${R.first_name} ${R.last_name}`
					}
				})

				postMessage({
					type: ev.data.type,
					auditors: result
				})
			})
			break

		// Список волн для страницы волн
		case 'waves':
			checkParam('token', 'page', 'pageSize', 'filters')

			params = {
				page: ev.data.page,
				page_size: ev.data.pageSize
			}

			if (ev.data.filters.client != '-1') params.customer = ev.data.filters.client
			if (ev.data.filters.status != '-1') params.distribution_status = ev.data.filters.status
			if (ev.data.filters.dateFrom) params.begin = ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.dateTo) params.end = ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.wave) params.name = ev.data.filters.wave

			API({
				name: 'monitoring_wave/',
				token: ev.data.token,
				getParams: params
			}, answer => {
				if (!('count' in answer))
					throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

				postMessage({
					type: ev.data.type,
					count: answer.count,
					waves: answer.count ? answer.results : []
				})
			})
			break

		// Подробная информация о волне
		case 'waveInfo':
			checkParam('token', 'id')

			API({
				name: `monitoring_wave/${ev.data.id}/`,
				token: ev.data.token
			}, answer => {
				API({
					name: `monitoring_wave/${ev.data.id}/retail_network_name/filter/`,
					token: ev.data.token
				}, nets => {
					postMessage({
						type: ev.data.type,
						waveInfo: answer,
						nets: nets
					})
				})
			})
			break

		// Добавление или редактирование волны
		// ev.data.method: add или edit
		case 'addWave':
			checkParam('token', 'data', 'method', 'id')

			if (typeof ev.data.data.dateFrom == 'string')
				ev.data.data.dateFrom = new Date(ev.data.data.dateFrom.replace(/\+(\d{2})(\d{2})$/, '+$1:$2'))
			if (typeof ev.data.data.dateTo == 'string')
				ev.data.data.dateTo = new Date(ev.data.data.dateTo.replace(/\+(\d{2})(\d{2})$/, '+$1:$2'))

			API({
				name: ev.data.method == 'add' ? 'monitoring_wave/' : `monitoring_wave/${ev.data.id}/`,
				token: ev.data.token,
				method: ev.data.method == 'add' ? 'post' : 'put',
				postData: JSON.stringify({
					begin: ev.data.data.dateFrom.toISOString(),
					end: ev.data.data.dateTo.toISOString(),
					customer: ev.data.data.client,
					name: ev.data.data.name
				})
			}, answer => {
				if (answer.id)
					postMessage({
						type: 'waveAdded',
						wave: answer.id
					})
			})
			break

		case 'checkWaveStatus':
			checkParam('token', 'id')

			API({
				name: `monitoring_wave/${ev.data.id}/`,
				token: ev.data.token
			}, answer => {
				postMessage({
					type: ev.data.type,
					id: ev.data.id,
					status: answer.distribution_status,
					dateFrom: answer.begin,
					dateTo: answer.end,
					client: answer.customer,
					name: answer.name
				})
			})
			break

		// Распределения волны
		case 'waveDistributions':
			checkParam('token', 'wave', 'filters')

			params = {
				page: 1,
				page_size: 1e5,
				monitoring_wave: ev.data.wave
			}

			if (ev.data.filters.tradePoint != -1) params.shop = ev.data.filters.tradePoint
			if (ev.data.filters.auditor != -1) params.auditor = ev.data.filters.auditor
			if (ev.data.filters.segment != -1) params.segment = ev.data.filters.segment
			if (ev.data.filters.town && ev.data.filters.town.length) params.address = ev.data.filters.town
			if (ev.data.filters.net && ev.data.filters.net != -1) params.retail_network_name = ev.data.filters.net

			API({
				name: 'monitoring_wave_task/',
				token: ev.data.token,
				getParams: params
			}, answer => {
				if (!('count' in answer))
					throw `на запрос ${ev.data.type} сервер прислал плохой ответ`

				postMessage({
					type: ev.data.type,
					count: answer.count,
					distributions: answer.count ? answer.results : []
				})
			})
			break

		// Создание распределения для волны
		case 'createDistribution':
			checkParam('token', 'distribution')

			API({
				name: 'monitoring_wave_task/',
				method: 'post',
				token: ev.data.token,
				postData: JSON.stringify(ev.data.distribution)
			}, answer => {
				postMessage({ type: 'distributionCreated' })
			})
			break

		case 'deleteDistribution':
			checkParam('token', 'id')

			// Ответ перехватывается костылём, потому что он без тела
			API({
				name: `monitoring_wave_task/${ev.data.id}/`,
				method: 'delete',
				token: ev.data.token
			})
			break

		// Загрузка файлов в волну
		case 'loadFileTT': case 'loadFileSegments':
			checkParam('token', 'wave', 'file')

			const loadParams = ev.data.type == 'loadFileTT' ? {
				fileName: 'tt.xlsx',
				address: 'shop',
				event: 'ttLoaded'
			} : {
				fileName: 'segments.xlsx',
				address: 'segment',
				event: 'segmentsLoaded'
			}

			const FD = new FormData
			FD.append('file', new Blob([ev.data.file]), loadParams.fileName)

			API({
				name: `monitoring_wave/${ev.data.wave}/import/${loadParams.address}/`,
				token: ev.data.token,
				contentType: 'auto',
				method: 'post',
				postData: FD
			}, answer => {
				checkCelery(answer.result_id, ev.data.token, answer => {
					if (answer.status == 'SUCCESS')
						postMessage({
							type: loadParams.event,
							wave: ev.data.wave
						})
					else
						postMessage({
							type: 'badImport',
							tab: ev.data.type == 'loadFileTT' ? 'tt' : 'segments'
						})
				})
			})
			break

		// Загрузка цен Ашана
		case 'loadFilePrices':
			checkParam('token', 'file')

			const FDP = new FormData
			FDP.append('file', new Blob([ev.data.file]), 'prices.xlsx')

			API({
				name: `sku/import_average_price/`,
				token: ev.data.token,
				contentType: 'auto',
				method: 'post',
				postData: FDP
			}, answer => {
				checkCelery(answer.result_id, ev.data.token, answer => {
					if (answer.status == 'SUCCESS')
						postMessage({
							type: 'pricesLoaded'
						})
					else
						postMessage({
							type: 'badImportPrices'
						})
				})
			})
			break

		// Список файлов для фильтра
		case 'filterFilesList':
			checkParam('token')

			API({
				name: 'shop/target_file_name/filter/',
				token: ev.data.token
			}, answer => {
				postMessage({
					type: ev.data.type,
					files: answer.filenames.map(F => { return {name: F} })
				})
			})
			break

		case 'exportRecords':
			checkParam('token', 'filters')

			if (ev.data.filters.wave == '-1') {
				postMessage({
					type: 'exportRejected-wave'
				})
				break
			}

			params = { monitoring_wave: ev.data.filters.wave }

			if (ev.data.filters.net != '-1') params.retail_network = ev.data.filters.net
			if (ev.data.filters.tradePoint != '-1') params.shop = ev.data.filters.tradePoint
			if (ev.data.filters.dateFrom) params.begin = ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.dateTo) params.end = ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1')
			if (ev.data.filters.segment && ev.data.filters.segment != '-1') params.segment = ev.data.filters.segment
			if (ev.data.filters.filterByFile && ev.data.filters.filterByFile != -1) params.shop_target_file_name = ev.data.filters.filterByFile

			API({
				name: 'sku_monitoring_data/export/',
				method: 'post',
				token: ev.data.token,
				getParams: params
			}, answer => {
				checkCelery(answer.result_id, ev.data.token, answer => {
					if (answer.status == 'SUCCESS')
						postMessage({
							type: 'exportRecords',
							links: answer.result
						})
					else
						postMessage({
							type: 'badExport'
						})
				})
			})
			break

		// Запрос списка групп пользователей
		case 'userGroups':
			checkParam('token')

			API({
				name: 'group/',
				token: ev.data.token
			}, answer => {
				postMessage({
					type: ev.data.type,
					groups: answer
				})
			})
			break

		case 'createOrUpdateUser':
			checkParam('token', 'method', 'user')

			// Нужно собрать правильный groups
			ev.data.user.groups = [ev.data.user.group]
			if (ev.data.user.mentorN && ev.data.user.mentorN != -1)
				ev.data.user.mentor = ev.data.user.mentorN
			if (ev.data.user.mentorN == -1)
				ev.data.user.mentor = null
			if (!ev.data.user.middle_name)
				ev.data.user.middle_name = ''

			API({
				name: ev.data.method == 'create'? 'user/' : `user/${ev.data.user.id}/`,
				token: ev.data.token,
				method: ev.data.method == 'create' ? 'post' : 'put',
				postData: JSON.stringify(ev.data.user)
			}, answer => {
				if (answer.id && ev.data.user.password)
					API({
						name: `user/${answer.id}/password/`,
						method: 'put',
						token: ev.data.token,
						postData: JSON.stringify({password: ev.data.user.password})
					}, answer => {
						postMessage({ type: 'userUpdated' })
					})
				else
					postMessage({ type: 'userUpdated' })
			})
			break

		// Подсказки по производителям по бренду
		case 'producersByBrand':
			checkParam('token', 'brand', 'id')

			API({
				name: 'sku/producer/filter/',
				token: ev.data.token,
				getParams: {
					brand: ev.data.brand
				}
			}, answer => {
				if ('producers' in answer)
					postMessage({
						type: 'producersSuggestions',
						producers: answer.producers,
						brandId: ev.data.id
					})
			})
			break

		// Запрос файлов статистики
		case 'statistics':
			checkParam('token', 'statType', 'filters')
			
			const statIndexes = {
				moderation: 1,
				segment:    2,
				auditor:    3,
				novelties:  4
			}

			if (!(ev.data.statType in statIndexes))
				break

			API({
				name: `statistic/report${statIndexes[ev.data.statType]}/`,
				token: ev.data.token,
				method: 'post',
				getParams: {
					begin: ev.data.filters.dateFrom.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1'),
					end: ev.data.filters.dateTo.replace(/^(\d+)\.(\d+)\.(\d+)$/, '$3-$2-$1'),
					monitoring_wave: ev.data.filters.wave
				}
			}, answer => {
				checkCelery(answer.result_id, ev.data.token, cel => {
					if (cel.status == 'SUCCESS')
						postMessage({
							type: 'exportDone',
							link: cel.result
						})
					else
						postMessage({
							type: 'badExport'
						})
				})
			})
			break

		// Перемещение записей из модерации в отправленные
		case 'ModerationToSent':
			checkParam('token', 'wave')

			API({
				name: `sku_monitoring_data/move/?monitoring_wave=${ev.data.wave}`,
				method: 'post',
				token: ev.data.token
			}, answer => {
				checkCelery(answer.result_id, ev.data.token, cel => {
					if (cel.status == 'SUCCESS')
						postMessage({
							type: 'moderationSent'
						})
					else
						postMessage({
							type: 'badModerationSend'
						})
				})
			})
			break
	}
}

function API(options, callback) {
	if (!options.method) options.method = 'GET'
	if (!options.name) {
		console.trace()
		throw 'Не передано имя для вызова API'
	}

	const headers = {}
	if (options.contentType) {
		if (options.contentType !== 'auto')
			headers['Content-Type'] = options.contentType
	}
	else
		headers['Content-Type'] = 'application/json'

	if (options.token) headers.Authorization = 'JWT ' + options.token

	options.name = API_ADDR + options.name

	const requestParams = {
		headers: headers,
		method: options.method.toUpperCase()
	}
	if (options.postData) requestParams.body = options.postData
	if (options.getParams) {
		let getParams = []

		Object.getOwnPropertyNames(options.getParams).forEach(param => {
			getParams.push(encodeURIComponent(param) + '=' + encodeURIComponent(options.getParams[param]))
		})

		if (getParams.length)
			options.name += '?' + getParams.join('&')
	}

	fetch(options.name, requestParams)
		.then(ret => {
			// Костыль, но деваться некуда, при удалении в ответе нет JSON-тела, парсер падает
			if (ret.status == 204 && /\/monitoring_wave_task\/[0-9a-f-]+\/$/.test(options.name)) {
				postMessage({ type: 'distributionDeleted' })
				return false
			}
			else if (ret.status == 204 && /\/sku_monitoring_data\/[0-9a-f-]+\//.test(options.name)) {
				postMessage({ type: 'recordDeleted' })
				return false
			}
			else if (ret.ok)
				return ret.json()

			APIErrorHandler(ret, options.name, options.method)

			throw `Сервер ответил ошибкой ${ret.status} на ${options.name}`
		})
		.then(response => {
			if (response == undefined) return
			if (typeof callback == 'function')
				callback.call(this, response)
			else
				console.info(response)
		})
		.catch(err => { console.error(`–→ ${err}`) })
}

API.ID = 0

function APIErrorHandler(ret, requestName, method) {
	switch (ret.status) {
		case 400:
			( new Promise((good, bad) => good(ret.json())) )
				.then(errBody => {
					if (errBody.non_field_errors)
						switch (errBody.non_field_errors[0]) {
							/* Не удалось войти или ошибка при попытке обновления токена */
							case 'Unable to log in with provided credentials.':
							case 'Error decoding signature.':
							case 'Signature has expired.':
								postMessage({
									type: 'login',
									result: 'fail'
								})
								break
						}
					else if (errBody.barcode && errBody.barcode.indexOf('sku with this barcode already exists.') != -1)
						postMessage({
							type: 'addFormError',
							field: 'barcode',
							error: 'SKU с указанным штрихкодом уже зарегистрирован'
						})
					else if (errBody.username) {
						if (errBody.username.indexOf('user with this Логин(номер сотового телефона) already exists.') != -1)
							postMessage({
								type: 'userExists'
							})
						else if (errBody.username.indexOf('is not an celpphone number') != -1)
							postMessage({
								type: 'badPhone'
							})
					}
				})
				.catch(err => console.warn(`Что-то не так. Код ${ret.status}: `  + err))
			break

		case 401:
			( new Promise((good, bad) => good(ret.json())) )
				.then(errBody => {
					if (errBody.detail)
						switch (errBody.detail) {

							/* Не удалось войти, нужно вернуться к вводу пароля */
							case 'Error decoding signature.':
								postMessage({
									type: 'login',
									result: 'fail'
								})
								break

							case 'Signature has expired.':
								postMessage({
									type: 'login',
									result: 'fail'
								})

							case 'Authentication credentials were not provided.':
								console.warn(`Забыл вместе с запросом ${method}/${requestName} отправить токен`)
								break
						}
				})
				.catch(err => console.warn(`Что-то не так. Код ${ret.status}: `  + err))
			break
	}
}

// Добавление sku к записи, если его там нет. res — запись.
// Так как объект передаётся по ссылке, то функция изменяет переданный объект
function addSkuToRecord(res) {
	if (res.status == 'new_barcode' && res.new_barcode !== null || res.status == 'deleted') {
		res.sku = {
			name:        '',
			brand:       '',
			barcode:     res.new_barcode,
			producer:    '',
			segment: {
				name: '-???-',
				code: (res.new_barcode_segment || 0)
			},
			srcName:     '',
			srcBrand:    '',
			srcBarcode:  res.new_barcode,
			srcProducer: '',
			srcSegment: {
				name: '-???-',
				code: (res.new_barcode_segment || 0)
			}
		}
	}
	else {
		res.sku.srcName     = res.sku.name
		res.sku.srcBrand    = res.sku.brand
		res.sku.srcBarcode  = res.sku.barcode
		res.sku.srcProducer = res.sku.producer
		res.sku.srcSegment  = {
			name: res.sku.segment.name,
			code: res.sku.segment.code
		}
	}

	return res
}

// Проверка состояния celery
function checkCelery(id, token, callback) {
	API({
		name: `celery/result/${id}/`,
		token: token
	}, answer => {
		const status = answer.status
		if (status == 'PENDING') {
			setTimeout(function() {
				checkCelery(id, token, callback)
			}, 1000)
		}
		else
			callback.call(this, answer)
	})
}